'use client'
import { cn, useSignal, useSignals } from '@cascivo/core'
import type { Signal } from '@cascivo/core'
import { createContext, useId, useRef } from 'react'
import type { HTMLAttributes, KeyboardEvent, ReactNode } from 'react'
import styles from './tabs.module.css'

interface TabsStore {
  active: Signal<string>
  setValue: (value: string) => void
  baseId: string
}

const TabsContext = createContext<TabsStore | null>(null)

export interface TabsProps {
  defaultValue?: string
  value?: string
  onValueChange?: (value: string) => void
  className?: string
  children: ReactNode
}

export function Tabs({ defaultValue, value, onValueChange, className, children }: TabsProps) {
  const baseId = useId()
  const active = useSignal(value ?? defaultValue ?? '')
  if (value !== undefined) active.value = value

  const store: TabsStore = {
    active,
    baseId,
    setValue: (next) => {
      if (value === undefined) active.value = next
      onValueChange?.(next)
    },
  }

  return (
    <TabsContext.Provider value={store}>
      <div className={cn(styles['tabs'], className)}>{children}</div>
    </TabsContext.Provider>
  )
}

export function TabsList({ className, children, ...props }: HTMLAttributes<HTMLDivElement>) {
  const ref = useRef<HTMLDivElement>(null)

  return (
    <TabsContext.Consumer>
      {(store) => {
        const handleKeyDown = (event: KeyboardEvent<HTMLDivElement>) => {
          if (!store || !['ArrowRight', 'ArrowLeft', 'Home', 'End'].includes(event.key)) return
          const tabs = Array.from(
            ref.current?.querySelectorAll<HTMLButtonElement>('[role="tab"]:not([disabled])') ?? [],
          )
          if (tabs.length === 0) return
          event.preventDefault()
          const current = tabs.findIndex((tab) => tab.dataset['value'] === store.active.value)
          let nextIndex = current
          if (event.key === 'ArrowRight') nextIndex = (current + 1) % tabs.length
          else if (event.key === 'ArrowLeft') nextIndex = (current - 1 + tabs.length) % tabs.length
          else if (event.key === 'Home') nextIndex = 0
          else if (event.key === 'End') nextIndex = tabs.length - 1
          const next = tabs[nextIndex]
          next?.focus()
          if (next?.dataset['value']) store.setValue(next.dataset['value'])
        }

        return (
          <div
            ref={ref}
            role="tablist"
            className={cn(styles['list'], className)}
            onKeyDown={handleKeyDown}
            {...props}
          >
            {children}
          </div>
        )
      }}
    </TabsContext.Consumer>
  )
}

export interface TabsTriggerProps extends HTMLAttributes<HTMLButtonElement> {
  value: string
  disabled?: boolean
}

export function TabsTrigger(props: TabsTriggerProps) {
  return (
    <TabsContext.Consumer>
      {(store) => (store ? <TabsTriggerInner store={store} {...props} /> : null)}
    </TabsContext.Consumer>
  )
}

function TabsTriggerInner({
  store,
  value,
  className,
  children,
  disabled,
  ...props
}: TabsTriggerProps & { store: TabsStore }) {
  useSignals()
  const selected = store.active.value === value

  return (
    <button
      type="button"
      role="tab"
      id={`${store.baseId}-trigger-${value}`}
      aria-selected={selected}
      aria-controls={`${store.baseId}-content-${value}`}
      tabIndex={selected ? 0 : -1}
      data-state={selected ? 'active' : 'inactive'}
      data-value={value}
      disabled={disabled}
      className={cn(styles['trigger'], className)}
      onClick={() => store.setValue(value)}
      {...props}
    >
      {children}
    </button>
  )
}

export interface TabsContentProps extends HTMLAttributes<HTMLDivElement> {
  value: string
}

export function TabsContent(props: TabsContentProps) {
  return (
    <TabsContext.Consumer>
      {(store) => (store ? <TabsContentInner store={store} {...props} /> : null)}
    </TabsContext.Consumer>
  )
}

function TabsContentInner({
  store,
  value,
  className,
  children,
  ...props
}: TabsContentProps & { store: TabsStore }) {
  useSignals()
  if (store.active.value !== value) return null

  return (
    <div
      role="tabpanel"
      id={`${store.baseId}-content-${value}`}
      aria-labelledby={`${store.baseId}-trigger-${value}`}
      tabIndex={0}
      className={cn(styles['content'], className)}
      {...props}
    >
      {children}
    </div>
  )
}

@layer cascivo.component {
  .tabs {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-4);
  }

  .list {
    display: flex;
    gap: var(--cascivo-space-1);
    border-block-end: 1px solid var(--cascivo-color-border);
    overflow-x: auto;
    flex-wrap: nowrap;
    scroll-snap-type: x proximity;
    scrollbar-width: thin;
    -webkit-overflow-scrolling: touch;
    overscroll-behavior-x: contain;
  }

  .trigger {
    position: relative;
    padding-inline: var(--cascivo-space-3);
    padding-block: var(--cascivo-space-2);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    color: var(--cascivo-color-text-subtle);
    background: transparent;
    border: none;
    cursor: pointer;
    transition: color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &::after {
      content: '';
      position: absolute;
      inset-inline: 0;
      inset-block-end: -1px;
      block-size: 2px;
      background-color: var(--cascivo-color-accent);
      scale: 0 1;
      transition: scale var(--cascivo-duration-150) var(--cascivo-ease-out);
    }

    &:hover:not(:disabled) {
      color: var(--cascivo-color-text);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
      border-radius: var(--cascivo-radius-control);
    }

    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }

    &[data-state='active'] {
      color: var(--cascivo-color-text);

      &::after {
        scale: 1 1;
      }
    }
  }

  .content {
    font-family: var(--cascivo-font-sans);
    color: var(--cascivo-color-text);

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
      border-radius: var(--cascivo-radius-control);
    }
  }
}

@media (forced-colors: active) {
  .list {
    border-block-end: 1px solid ButtonText;
  }

  .trigger[data-state='active'] {
    border-block-end: 2px solid Highlight;
  }

  .trigger:focus-visible {
    outline: 2px solid Highlight;
    outline-offset: 2px;
  }
}
